# solution.py
"""FamilyCodeQuest -- Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that powers the multiplayer
"FamilyCodeQuest" coding platform. It manages users, projects (coding quests),
tasks (challenges), threaded messaging with attachments, a performance
dashboard (completion rate, average completion time, peer ratings) and a small
reporting engine that can export to CSV and PDF.

The module is intentionally dependency-free (standard library only) so it runs
anywhere a family might want to learn to code together.

Design highlights
-----------------
* A single shared :class:`_Store` holds every record and index and a single
  re-entrant lock. Each domain service (``users``, ``projects``, ``tasks``,
  ``messages``, ``performance``, ``reports``) shares that one lock so the whole
  manager is safe under heavy concurrent load.
* All public reads return deep copies, so callers can never mutate internal
  state by accident.
* Identifiers are globally unique and monotonically increasing across every
  record type, starting at ``1``.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Set, Tuple

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle state of a challenge/task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Role a participant plays on the platform."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kinds of reports the engine can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Domain records
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    data: bytes = b""


@dataclass
class User:
    """A platform participant (child or adult)."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A coding quest that groups related challenges."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A single coding challenge inside a project."""

    id: int
    project_id: int
    title: str
    description: str
    assignee_id: Optional[int]
    status: TaskStatus
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    """A message posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)


@dataclass
class Rating:
    """A peer rating with optional written feedback."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared store (data + indexes + lock + id generator)
# ---------------------------------------------------------------------------
class _Store:
    """Holds every record, secondary index, the shared lock and id counter.

    Every domain service references the same ``_Store`` instance, so a single
    lock guards all mutations and reads.
    """

    def __init__(self, now):
        self.lock = threading.RLock()
        self._now_fn = now if now is not None else datetime.now
        self._next_id = 1

        # Primary records.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}

        # Secondary indexes.
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.tasks_by_project: Dict[int, Set[int]] = {}
        self.tasks_by_assignee: Dict[int, Set[int]] = {}
        self.messages_by_project: Dict[int, Set[int]] = {}
        self.messages_by_task: Dict[int, Set[int]] = {}
        self.ratings_by_ratee: Dict[int, List[Rating]] = {}

    # -- helpers ----------------------------------------------------------
    def now(self) -> datetime:
        return self._now_fn()

    def next_id(self) -> int:
        nid = self._next_id
        self._next_id += 1
        return nid

    @staticmethod
    def add_index(index: Dict[int, Set[int]], key: int, value: int) -> None:
        index.setdefault(key, set()).add(value)

    @staticmethod
    def remove_index(index: Dict[int, Set[int]], key: int, value: int) -> None:
        bucket = index.get(key)
        if bucket is not None:
            bucket.discard(value)
            if not bucket:
                del index[key]


# ---------------------------------------------------------------------------
# Validation helpers
# ---------------------------------------------------------------------------
def _require_non_empty(value: str, label: str) -> str:
    if not isinstance(value, str) or not value.strip():
        raise ValidationError("{0} must be a non-empty string".format(label))
    return value.strip()


def _validate_email(email: str) -> str:
    if not isinstance(email, str):
        raise ValidationError("email must be a string")
    cleaned = email.strip()
    if not cleaned or "@" not in cleaned:
        raise ValidationError("a valid email address is required")
    return cleaned


# ---------------------------------------------------------------------------
# Domain services -- all share one store / one lock
# ---------------------------------------------------------------------------
class _BaseService:
    def __init__(self, store: _Store):
        self._store = store
        self._lock = store.lock


class _UserService(_BaseService):
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        name = _require_non_empty(username, "username")
        mail = _validate_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")
        with self._lock:
            store = self._store
            if name in store.username_index:
                raise DuplicateError("username already in use")
            if mail in store.email_index:
                raise DuplicateError("email already in use")
            user = User(
                id=store.next_id(),
                username=name,
                email=mail,
                role=role,
                created_at=store.now(),
            )
            store.users[user.id] = user
            store.username_index[name] = user.id
            store.email_index[mail] = user.id
            return copy.deepcopy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return copy.deepcopy(self._get_live(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self._store.users.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            store = self._store
            user = self._get_live(user_id)

            new_name = None
            if username is not None:
                new_name = _require_non_empty(username, "username")
                owner = store.username_index.get(new_name)
                if owner is not None and owner != user.id:
                    raise DuplicateError("username already in use")

            new_mail = None
            if email is not None:
                new_mail = _validate_email(email)
                owner = store.email_index.get(new_mail)
                if owner is not None and owner != user.id:
                    raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_name is not None:
                del store.username_index[user.username]
                store.username_index[new_name] = user.id
                user.username = new_name
            if new_mail is not None:
                del store.email_index[user.email]
                store.email_index[new_mail] = user.id
                user.email = new_mail
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            store = self._store
            user = self._get_live(user_id)

            for project in store.projects.values():
                if project.owner_id == user.id:
                    raise ConflictError("user owns one or more projects")

            assigned = store.tasks_by_assignee.get(user.id, set())
            for task_id in assigned:
                task = store.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")

            # Detach completed tasks, then remove the user.
            for task_id in list(assigned):
                task = store.tasks.get(task_id)
                if task is not None:
                    task.assignee_id = None
            store.tasks_by_assignee.pop(user.id, None)
            del store.username_index[user.username]
            del store.email_index[user.email]
            del store.users[user.id]

    # -- internal ---------------------------------------------------------
    def _get_live(self, user_id) -> User:
        user = self._store.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user


class _ProjectService(_BaseService):
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        clean_name = _require_non_empty(name, "project name")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")
        with self._lock:
            store = self._store
            if owner_id not in store.users:
                raise NotFoundError("owner {0} not found".format(owner_id))
            project = Project(
                id=store.next_id(),
                name=clean_name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=store.now(),
            )
            store.projects[project.id] = project
            return copy.deepcopy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return copy.deepcopy(self._get_live(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(self._store.projects.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in projects]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None) -> Project:
        with self._lock:
            project = self._get_live(project_id)

            new_name = None
            if name is not None:
                new_name = _require_non_empty(name, "project name")

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            if new_name is not None:
                project.name = new_name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            store = self._store
            project = self._get_live(project_id)

            for task_id in list(store.tasks_by_project.get(project.id, set())):
                task = store.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    store.remove_index(
                        store.tasks_by_assignee, task.assignee_id, task_id
                    )
                for msg_id in list(store.messages_by_task.get(task_id, set())):
                    store.messages.pop(msg_id, None)
                store.messages_by_task.pop(task_id, None)
            store.tasks_by_project.pop(project.id, None)

            for msg_id in list(store.messages_by_project.get(project.id, set())):
                store.messages.pop(msg_id, None)
            store.messages_by_project.pop(project.id, None)

            del store.projects[project.id]

    # -- internal ---------------------------------------------------------
    def _get_live(self, project_id) -> Project:
        project = self._store.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project


class _TaskService(_BaseService):
    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                    description="") -> Task:
        with self._lock:
            store = self._store
            if project_id not in store.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            clean_title = _require_non_empty(title, "task title")
            if assignee_id is not None and assignee_id not in store.users:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            project = store.projects[project_id]
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task = Task(
                id=store.next_id(),
                project_id=project_id,
                title=clean_title,
                description=description or "",
                assignee_id=assignee_id,
                status=TaskStatus.NOT_STARTED,
                deadline=deadline,
                created_at=store.now(),
            )
            store.tasks[task.id] = task
            store.add_index(store.tasks_by_project, project_id, task.id)
            if assignee_id is not None:
                store.add_index(store.tasks_by_assignee, assignee_id, task.id)
            return copy.deepcopy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return copy.deepcopy(self._get_live(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            store = self._store
            if project_id not in store.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = store.tasks_by_project.get(project_id, set())
            tasks = sorted((store.tasks[i] for i in ids), key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            store = self._store
            if assignee_id not in store.users:
                raise NotFoundError("user {0} not found".format(assignee_id))
            ids = store.tasks_by_assignee.get(assignee_id, set())
            tasks = sorted((store.tasks[i] for i in ids), key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            store = self._store
            task = self._get_live(task_id)
            if assignee_id not in store.users:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._get_live(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            store = self._store
            task = self._get_live(task_id)
            if deadline is not None:
                project = store.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            store = self._store
            task = self._get_live(task_id)
            now = store.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # -- internal ---------------------------------------------------------
    def _set_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        store = self._store
        if task.assignee_id is not None:
            store.remove_index(store.tasks_by_assignee, task.assignee_id, task.id)
        if assignee_id is not None:
            store.add_index(store.tasks_by_assignee, assignee_id, task.id)
        task.assignee_id = assignee_id

    def _get_live(self, task_id) -> Task:
        task = self._store.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task


class _MessageService(_BaseService):
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        with self._lock:
            store = self._store
            if author_id not in store.users:
                raise NotFoundError("author {0} not found".format(author_id))
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None and project_id not in store.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in store.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            if parent_id is not None and parent_id not in store.messages:
                raise NotFoundError("parent {0} not found".format(parent_id))

            built = self._build_attachments(attachments, author_id, store)
            if not (body and body.strip()) and not built:
                raise ValidationError("message body or an attachment is required")

            message = Message(
                id=store.next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=store.now(),
                attachments=built,
            )
            store.messages[message.id] = message
            if project_id is not None:
                store.add_index(store.messages_by_project, project_id, message.id)
            else:
                store.add_index(store.messages_by_task, task_id, message.id)
            return copy.deepcopy(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._get_live(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not (new_body and new_body.strip()) and not message.attachments:
                raise ValidationError("message body cannot be empty")
            message.body = new_body
            message.edited_at = self._store.now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            store = self._store
            message = self._get_live(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach files")
            clean_name = _require_non_empty(filename, "filename")
            payload = data if data is not None else b""
            message.attachments.append(
                Attachment(
                    filename=clean_name,
                    size=len(payload),
                    uploaded_by=uploader_id,
                    uploaded_at=store.now(),
                    data=bytes(payload),
                )
            )
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            store = self._store
            if project_id not in store.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = store.messages_by_project.get(project_id, set())
            msgs = sorted((store.messages[i] for i in ids), key=lambda m: m.id)
            return [copy.deepcopy(m) for m in msgs]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            store = self._store
            if task_id not in store.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            ids = store.messages_by_task.get(task_id, set())
            msgs = sorted((store.messages[i] for i in ids), key=lambda m: m.id)
            return [copy.deepcopy(m) for m in msgs]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            store = self._store
            message = self._get_live(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            if message.project_id is not None:
                store.remove_index(
                    store.messages_by_project, message.project_id, message.id
                )
            if message.task_id is not None:
                store.remove_index(
                    store.messages_by_task, message.task_id, message.id
                )
            del store.messages[message.id]

    # -- internal ---------------------------------------------------------
    def _build_attachments(self, attachments, author_id, store) -> List[Attachment]:
        built: List[Attachment] = []
        if not attachments:
            return built
        uploaded_at = store.now()
        for item in attachments:
            filename, data = item
            clean_name = _require_non_empty(filename, "filename")
            payload = data if data is not None else b""
            built.append(
                Attachment(
                    filename=clean_name,
                    size=len(payload),
                    uploaded_by=author_id,
                    uploaded_at=uploaded_at,
                    data=bytes(payload),
                )
            )
        return built

    def _get_live(self, message_id) -> Message:
        message = self._store.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message


class _PerformanceService(_BaseService):
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(user_id)
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            store = self._store
            self._require_user(rater_id, "rater")
            self._require_user(ratee_id, "ratee")
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None and task_id not in store.tasks:
                raise NotFoundError("task {0} not found".format(task_id))

            rating = Rating(
                id=store.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=store.now(),
            )
            store.ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._store.ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(user_id)
            avg_time = (sum(durations) / len(durations)) if durations else None
            ratings = self._store.ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_avg = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_avg,
            }

    # -- internal ---------------------------------------------------------
    def _require_user(self, user_id, label="user") -> None:
        if user_id not in self._store.users:
            raise NotFoundError("{0} {1} not found".format(label, user_id))

    def _assigned_tasks(self, user_id) -> List[Task]:
        store = self._store
        ids = store.tasks_by_assignee.get(user_id, set())
        return [store.tasks[i] for i in ids]

    def _completion_durations(self, user_id) -> List[float]:
        durations = []
        for task in self._assigned_tasks(user_id):
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations


class _ReportService(_BaseService):
    def __init__(self, store: _Store, performance: _PerformanceService):
        super().__init__(store)
        self._performance = performance

    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            store = self._store
            if project_id not in store.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            now = store.now()
            ids = store.tasks_by_project.get(project_id, set())
            tasks = [store.tasks[i] for i in ids]
            total = len(tasks)

            status_counts = {s.value: 0 for s in TaskStatus}
            completed = 0
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"]
                    if bucket["total"]
                    else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            store = self._store
            if project_id is not None and project_id not in store.projects:
                raise NotFoundError("project {0} not found".format(project_id))

            if project_id is None:
                user_ids = sorted(store.users.keys())
                scope_ids = None
            else:
                scope_ids = store.tasks_by_project.get(project_id, set())
                seen = []
                for task_id in scope_ids:
                    assignee = store.tasks[task_id].assignee_id
                    if assignee is not None and assignee not in seen:
                        seen.append(assignee)
                user_ids = sorted(seen)

            rows = [self._user_row(uid, scope_ids) for uid in user_ids]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            store = self._store
            if user_id not in store.users:
                raise NotFoundError("user {0} not found".format(user_id))
            row = self._user_row(user_id, None)
            ids = store.tasks_by_assignee.get(user_id, set())
            tasks = sorted((store.tasks[i] for i in ids), key=lambda t: t.id)
            row["report_type"] = ReportType.INDIVIDUAL_PERFORMANCE.value
            row["tasks"] = [
                {
                    "id": t.id,
                    "title": t.title,
                    "project_id": t.project_id,
                    "status": t.status.value,
                    "deadline": t.deadline,
                }
                for t in tasks
            ]
            return row

    def export_report(self, report, fmt) -> object:
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    # -- internal ---------------------------------------------------------
    def _user_row(self, user_id, scope_ids) -> dict:
        store = self._store
        all_ids = store.tasks_by_assignee.get(user_id, set())
        if scope_ids is not None:
            ids = all_ids & scope_ids
        else:
            ids = all_ids
        tasks = [store.tasks[i] for i in ids]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
        not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        avg_time = (sum(durations) / len(durations)) if durations else None

        ratings = store.ratings_by_ratee.get(user_id, [])
        rating_count = len(ratings)
        rating_avg = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        user = store.users.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user else "",
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_avg,
        }

    @staticmethod
    def _cell(value) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list, tuple)):
            return str(value)
        return str(value)

    def _to_csv(self, report) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            headers: List[str] = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row.keys():
                        if key not in headers:
                            headers.append(key)
            if not headers:
                headers = ["report_type"]
                writer.writerow(headers)
                writer.writerow([report.get("report_type", "")])
            else:
                writer.writerow(headers)
                for row in rows:
                    writer.writerow([self._cell(row.get(h)) for h in headers])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._cell(value)])
        return output.getvalue()

    def _to_pdf(self, report) -> bytes:
        lines = self._report_to_lines(report)
        return _build_pdf(lines)

    def _report_to_lines(self, report) -> List[str]:
        lines = ["FamilyCodeQuest Report"]
        report_type = report.get("report_type")
        if report_type:
            lines.append("Type: {0}".format(report_type))
        rows = report.get("rows")
        if isinstance(rows, list):
            for row in rows:
                if isinstance(row, dict):
                    parts = ["{0}={1}".format(k, self._cell(v))
                             for k, v in row.items()]
                    lines.append("; ".join(parts))
        else:
            for key, value in report.items():
                lines.append("{0}: {1}".format(key, self._cell(value)))
        return lines


# ---------------------------------------------------------------------------
# Minimal PDF builder (valid single-page document, standard library only)
# ---------------------------------------------------------------------------
def _escape_pdf_text(text: str) -> str:
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _build_pdf(text_lines: List[str]) -> bytes:
    if not text_lines:
        text_lines = [""]

    content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(text_lines):
        safe = _escape_pdf_text(line)
        if index == 0:
            content_parts.append("({0}) Tj".format(safe))
        else:
            content_parts.append("T*")
            content_parts.append("({0}) Tj".format(safe))
    content_parts.append("ET")
    stream = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        (
            b"<< /Length " + str(len(stream)).encode("latin-1") + b" >>\n"
            b"stream\n" + stream + b"\nendstream"
        ),
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray()
    out += b"%PDF-1.4\n"
    offsets = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += "{0} 0 obj\n".format(number).encode("latin-1")
        out += body
        out += b"\nendobj\n"

    xref_pos = len(out)
    size = len(objects) + 1
    out += "xref\n0 {0}\n".format(size).encode("latin-1")
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
    out += b"trailer\n"
    out += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("latin-1")
    out += b"startxref\n"
    out += "{0}\n".format(xref_pos).encode("latin-1")
    out += b"%%EOF\n"
    return bytes(out)


